<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            loadKey: 0,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                        astype: "SelectField",
                        label: this.$t("ClientName"),
                        name: "ClientName",
                        value: "",
                        placeholder: this.$t('Select') + " " + this.$t('Client'),
                        mode: "tag",
                        config: {
                            options: []
                        }
                    },
                    {
                        astype: "MultiSelectField",
                        label: this.$t("Cost Center"),
                        name: "CostCenter",
                        value: "",
                        placeholder: this.$t('Select'),
                        mode: "tag",
                        config: {
                            options: []
                        }
                    },
                    {
                        astype: "SelectField",
                        label: this.$t("Search By"),
                        name: "Searchby",
                        value: "",
                        placeholder: this.$t('Select'),
                        mode: "tag",
                        config: {
                            options: [{
                                name: 'Invoice Date',
                                value: 'INV'
                            }, {
                                name: 'Work Date',
                                value: 'WD'
                            }]
                        }
                    },
                    {
                        astype: "DateRangeField",
                        label: this.$t('Date'),
                        name: "DateFrom",
                        value: "",
                        placeholder: "",
                        config: {
                            format: "MM/DD/YYYY",
                            maxDate: false,
                            onChange: this.setTimerDate,
                            datePickerConfig: {
                                useCurrent: true,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                            secondDatePickerConfig: {
                                useCurrent: false,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                        },
                        validationRules: {
                            "required": false
                        },
                    }
                ]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetCostCenters();
    },
    methods: {
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "dtFrom") {
                vm.$refs.BarcodeReport.updateProperty("dtTo", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            vm.DateFrom = vm.$refs.BarcodeReport.getPropertyValue("DateFrom", "value");
            vm.DateTo = vm.$refs.BarcodeReport.getPropertyValue("DateFrom", "secondValue");

            let myObj = {
                reportName: "usicrevenuebycustomerdistrictdatenongrouped",
                ClientIds: e.ClientName,
                DistrictId: e.CostCenter.length > 0 ? e.CostCenter.map(item => item.value).join(",") : '',
                SearchBy: e.Searchby,
                dateFrom: vm.formatDate(vm.DateFrom),
                dateTo: vm.formatDate(vm.DateTo)
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            (vm.FormSchema)[0].Data[3].secondValue = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            await DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            })
        },
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    CostCentresData.forEach(item => {
                        vm.FormSchema[0].Data[1].config.options.push({
                            name: item.text,
                            value: item.value
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            })
        }
    }
}
</script>