<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            loadKey: 0,
            DataLoaded: 0,
            DateFormat: "M/D/YYYY",
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Client Name"),
                            name: "Clientname",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Client'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.GetUtilityByClient
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Utility Name"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Modified By"),
                            name: "ModifiedBy",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                      {
                            astype: "DateRangeField",
                            label: this.$t('Resolved Date'),
                            name: "ResolvedDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Flag Date'),
                            name: "FlagDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "textField",
                            label: this.$t("Ticket Number"),
                            name: "TicketNumber",
                            value: "",
                            placeholder: "Ticket Number"
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "DateRangeField",
                            label: this.$t('Work_Date'),
                            name: "WorkDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("Cost Centers"),
                            name: "CostCenters",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DateFormat = vm.GetUserInfo.DateFormat || "M/D/YYYY"; 
        vm.DataLoaded = 1;
        await vm.GetCostCenters();
        await vm.GetClient();
        await vm.GetUsers();
    },
    methods: {
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "ResolvedFromdate") {
                vm.$refs.BarcodeReport.updateProperty("ResolvedToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "FlagFromdate") {
                vm.$refs.BarcodeReport.updateProperty("FlagToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
            if (y.name == "WorkDateFromdate") {
                vm.$refs.BarcodeReport.updateProperty("WorkDateToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[0].secondValue = '';
            (vm.FormSchema)[2].Data[1].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0; 
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom=null&search=null&userId=null';
            await DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUtilityByClient: async function (x, y, z) {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            vm.FormSchema[0].Data[1].value = '';
            var ClientIds = y.value; 
            var url = `clientId=${ClientIds}&configid=0&Reqfrom=&clientIds=`;
            await DataServices.GetUtilityByClient(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.UTILITY_NAME,
                            value: element.UTILITY_ID
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUsers: async function () {
            var vm = this;
            var params = `isType=false&moduleName=InvoiceReport`;
            await DataServices.GetUsers(params).then((response) => {
                if (response.data != '') {
                    var UsersData = response.data;
                    UsersData.forEach(item => {
                        vm.FormSchema[0].Data[2].config.options.push({
                            name: item.UserName,
                            value: item.UserId
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    CostCentresData.forEach(item => {
                        vm.FormSchema[2].Data[1].config.options.push({
                            name: item.text,
                            value: item.value
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now(); 
            vm.reportPath = '';
            vm.parameter = [];
            vm.ResolvedDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ResolvedDateFrom", "value");
            vm.ResolvedDateTo = vm.$refs.BarcodeReport.getPropertyValue("ResolvedDateFrom", "secondValue");
            vm.FlagDateFrom = vm.$refs.BarcodeReport.getPropertyValue("FlagDateFrom", "value");
            vm.FlagDateTo = vm.$refs.BarcodeReport.getPropertyValue("FlagDateFrom", "secondValue");
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");

            let myObj = {
                reportName: "flagdetailreport",
                ClientIds: e.Clientname ? e.Clientname.toString() : '',

                UtilityIds: Array.isArray(e.UtilityName) && e.UtilityName.length > 0 ?
                    e.UtilityName.map(item => item.value).join(",") : '',

                userIds: Array.isArray(e.ModifiedBy) && e.ModifiedBy.length > 0 ?
                    e.ModifiedBy.map(item => item.value).join(",") : '',

                resolvedFromDate: vm.formatDate(vm.ResolvedDateFrom) ? vm.formatDate(vm.ResolvedDateFrom) : null,

                resolvedToDate: vm.formatDate(vm.ResolvedDateTo) ? vm.formatDate(vm.ResolvedDateTo) : null,

                createdFromDate: vm.formatDate(vm.FlagDateFrom) ? vm.formatDate(vm.FlagDateFrom) : null,

                createdToDate: vm.formatDate(vm.FlagDateTo) ? vm.formatDate(vm.FlagDateTo) : null,

                TicketNumber: e.TicketNumber || '',

                WorkDateFrom: vm.formatDate(vm.WorkDateFrom) ? vm.formatDate(vm.WorkDateFrom) : null,

                WorkDateTo: vm.formatDate(vm.WorkDateTo) ? vm.formatDate(vm.WorkDateTo) : null,

                CostCenterId: e.CostCenters || ''
            };

            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        }
    }
};
</script>